if (! function_exists('data_outlier_detector')) {
    function data_outlier_detector($values, $iqr_multiplier = null, $method = null)
    {
        if (!is_array($values) || count($values) < 4) {
            return json_encode(['error' => 'At least 4 values required for outlier detection', 'outliers' => []]);
        }
        $data = array_values($values);
        $n = count($data);
        $multiplier = isset($iqr_multiplier) ? (float)$iqr_multiplier : 1.5;
        $method = isset($method) ? $method : 'iqr';

        $sorted = $data;
        sort($sorted);

        // Percentile calculation using linear interpolation
        $percentile = function($sorted, $p) {
            $n = count($sorted);
            $rank = ($p / 100) * ($n - 1);
            $lower = floor($rank);
            $upper = ceil($rank);
            if ($lower === $upper) return $sorted[(int)$rank];
            return $sorted[(int)$lower] + ($rank - $lower) * ($sorted[(int)$upper] - $sorted[(int)$lower]);
        };

        $q1 = $percentile($sorted, 25);
        $q2 = $percentile($sorted, 50);
        $q3 = $percentile($sorted, 75);
        $iqr = $q3 - $q1;
        $lowerFence = $q1 - $multiplier * $iqr;
        $upperFence = $q3 + $multiplier * $iqr;

        // Mean and std for z-score method
        $mean = array_sum($data) / $n;
        $variance = 0;
        for ($i = 0; $i < $n; $i++) {
            $variance += ($data[$i] - $mean) * ($data[$i] - $mean);
        }
        $std = sqrt($variance / $n);

        // Detect outliers
        $iqrOutliers = [];
        $zscoreOutliers = [];

        for ($i = 0; $i < $n; $i++) {
            $val = $data[$i];

            // IQR method
            if ($val < $lowerFence || $val > $upperFence) {
                $iqrOutliers[] = [
                    'index' => $i,
                    'value' => $val,
                    'type' => $val < $lowerFence ? 'below_lower_fence' : 'above_upper_fence',
                ];
            }

            // Z-score method
            $zScore = $std > 0 ? abs($val - $mean) / $std : 0;
            if ($zScore > 3.0) {
                $zscoreOutliers[] = [
                    'index' => $i,
                    'value' => $val,
                    'z_score' => round($zScore, 4),
                ];
            }
        }

        $result = [
            'n' => $n,
            'method_used' => $method,
            'iqr_multiplier' => $multiplier,
            'summary' => [
                'min' => min($data),
                'max' => max($data),
                'mean' => round($mean, 4),
                'median' => $q2,
                'q1' => round($q1, 4),
                'q3' => round($q3, 4),
                'iqr' => round($iqr, 4),
                'lower_fence' => round($lowerFence, 4),
                'upper_fence' => round($upperFence, 4),
                'std_dev' => round($std, 4),
            ],
        ];

        $outlierCount = 0;
        if ($method === 'iqr' || $method === 'both') {
            $result['iqr_outliers'] = $iqrOutliers;
            $result['iqr_outlier_count'] = count($iqrOutliers);
            $outlierCount = count($iqrOutliers);
        }
        if ($method === 'zscore' || $method === 'both') {
            $result['zscore_outliers'] = $zscoreOutliers;
            $result['zscore_outlier_count'] = count($zscoreOutliers);
            if ($method === 'zscore') $outlierCount = count($zscoreOutliers);
            if ($method === 'both') $outlierCount = count($iqrOutliers) + count($zscoreOutliers);
        }

        $result['outlier_percentage'] = round($outlierCount / $n * 100, 2);
        $result['outlier_count'] = $outlierCount;

        return json_encode($result);
    }
